import React, { useState } from 'react';
import {
  Box,
  Paper,
  TextField,
  Button,
  Typography,
  Link,
  Alert,
  CircularProgress,
  Container,
  InputAdornment,
  IconButton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Grid,
  Card,
  CardContent,
  Chip
} from '@mui/material';
import {
  Visibility,
  VisibilityOff,
  Email,
  Lock,
  Instagram,
  YouTube,
  Telegram as TelegramIcon,
  Close,
  Payment,
  Subscriptions,
  AccountBalance,
  ShoppingCart
} from '@mui/icons-material';
import { Link as RouterLink } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useAuth } from '../../contexts/AuthContext';

const Login = () => {
  const { login } = useAuth();
  const [formData, setFormData] = useState({
    email: '',
    password: ''
  });
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [showPaymentModal, setShowPaymentModal] = useState(false);

  // Opções de pagamento
  const paymentOptions = {
    subscription: {
      title: "🚀 Assinar Nautilus",
      price: "R$ 299,99/mês",
      link: "https://pay.hub.la/tmF5YtOlGb1GDVFSam7S",
      color: "success"
    },
    recharge: [
      { value: 'R$ 9,00', link: 'https://pay.hub.la/ekfJp2uXQ0S5ZBb65Otb', isTest: true, desc: '(Teste)' },
      { value: 'R$ 50,00', link: 'https://pay.hub.la/MdORdaFcTzWvhT9IkZHP', desc: '' },
      { value: 'R$ 100,00', link: 'https://pay.hub.la/mFfwQbUAqILTw8bfDXjo', desc: '' },
      { value: 'R$ 200,00', link: 'https://pay.hub.la/EVrxnuDyf4JeB0uIYaFC', desc: '' },
      { value: 'R$ 500,00', link: 'https://pay.hub.la/LmFhy6R6HP3fjoJxZe5z', desc: '' }
    ]
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      await login(formData.email, formData.password);
      toast.success('Login realizado com sucesso!');
    } catch (error) {
      const errorMessage = error.response?.data?.message || 'Erro ao fazer login. Verifique suas credenciais.';
      setError(errorMessage);
      toast.error(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  const togglePasswordVisibility = () => {
    setShowPassword(!showPassword);
  };

  const handleOpenPaymentModal = () => {
    setShowPaymentModal(true);
  };

  const handleClosePaymentModal = () => {
    setShowPaymentModal(false);
  };

  const handlePaymentClick = (link) => {
    window.open(link, '_blank', 'noopener,noreferrer');
  };

  // Dados de mercado simulados para animação
  const cryptoSymbols = ['₿', 'Ξ', '◇', '⟐', '$'];
  const marketData = ['$67,234', '$3,421', '$156.78', '$0.52', '+12.5%', '-3.2%', '+8.7%'];

  return (
    <Box
      sx={{
        minHeight: '100vh',
        position: 'relative',
        overflow: 'hidden',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        padding: 2,
        background: 'linear-gradient(135deg, #0a0e1a 0%, #1a1f2e 50%, #0a0e1a 100%)',
        '&::before': {
          content: '""',
          position: 'absolute',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          backgroundImage: `
            repeating-linear-gradient(
              90deg,
              transparent,
              transparent 98px,
              rgba(0, 255, 100, 0.03) 100px,
              rgba(0, 255, 100, 0.03) 102px
            ),
            repeating-linear-gradient(
              0deg,
              transparent,
              transparent 98px,
              rgba(0, 255, 100, 0.03) 100px,
              rgba(0, 255, 100, 0.03) 102px
            )
          `,
          animation: 'gridMove 20s linear infinite',
          pointerEvents: 'none'
        },
        '@keyframes gridMove': {
          '0%': { transform: 'translate(0, 0)' },
          '100%': { transform: 'translate(100px, 100px)' }
        },
        '@keyframes float': {
          '0%, 100%': { transform: 'translateY(0px) rotate(0deg)', opacity: 0.6 },
          '50%': { transform: 'translateY(-20px) rotate(180deg)', opacity: 1 }
        },
        '@keyframes slidePrice': {
          '0%': { transform: 'translateX(-100px)', opacity: 0 },
          '10%': { opacity: 1 },
          '90%': { opacity: 1 },
          '100%': { transform: 'translateX(100vw)', opacity: 0 }
        },
        '@keyframes candlestick': {
          '0%': { scaleY: 0.8, opacity: 0.4 },
          '50%': { scaleY: 1.2, opacity: 0.8 },
          '100%': { scaleY: 0.8, opacity: 0.4 }
        }
      }}
    >
      {/* Símbolos de criptomoedas flutuantes */}
      {cryptoSymbols.map((symbol, index) => (
        <Box
          key={index}
          sx={{
            position: 'absolute',
            fontSize: '24px',
            color: 'rgba(0, 255, 100, 0.3)',
            animation: 'float 6s ease-in-out infinite',
            animationDelay: `${index * 1.2}s`,
            left: `${15 + index * 20}%`,
            top: `${20 + (index % 2) * 30}%`,
            pointerEvents: 'none',
            fontWeight: 'bold'
          }}
        >
          {symbol}
        </Box>
      ))}

      {/* Dados de mercado deslizantes */}
      {marketData.map((data, index) => (
        <Box
          key={index}
          sx={{
            position: 'absolute',
            top: `${10 + index * 12}%`,
            left: 0,
            fontSize: '14px',
            color: data.includes('+') ? 'rgba(0, 255, 100, 0.6)' : data.includes('-') ? 'rgba(255, 100, 100, 0.6)' : 'rgba(255, 255, 255, 0.4)',
            animation: 'slidePrice 8s linear infinite',
            animationDelay: `${index * 1.5}s`,
            pointerEvents: 'none',
            fontFamily: 'monospace',
            fontWeight: 'bold'
          }}
        >
          {data}
        </Box>
      ))}

      {/* Gráficos de candlestick simulados */}
      {Array.from({ length: 15 }).map((_, index) => (
        <Box
          key={`candle-${index}`}
          sx={{
            position: 'absolute',
            bottom: '10%',
            left: `${5 + index * 6}%`,
            width: '3px',
            height: `${20 + Math.random() * 40}px`,
            backgroundColor: Math.random() > 0.5 ? 'rgba(0, 255, 100, 0.3)' : 'rgba(255, 100, 100, 0.3)',
            animation: 'candlestick 3s ease-in-out infinite',
            animationDelay: `${index * 0.2}s`,
            pointerEvents: 'none',
            '&::before': {
              content: '""',
              position: 'absolute',
              top: '-10px',
              left: '50%',
              transform: 'translateX(-50%)',
              width: '1px',
              height: '10px',
              backgroundColor: 'inherit'
            },
            '&::after': {
              content: '""',
              position: 'absolute',
              bottom: '-10px',
              left: '50%',
              transform: 'translateX(-50%)',
              width: '1px',
              height: '10px',
              backgroundColor: 'inherit'
            }
          }}
        />
      ))}

      {/* Partículas flutuantes */}
      {Array.from({ length: 20 }).map((_, index) => (
        <Box
          key={`particle-${index}`}
          sx={{
            position: 'absolute',
            width: '2px',
            height: '2px',
            backgroundColor: 'rgba(0, 255, 100, 0.4)',
            borderRadius: '50%',
            left: `${Math.random() * 100}%`,
            top: `${Math.random() * 100}%`,
            animation: 'float 8s ease-in-out infinite',
            animationDelay: `${Math.random() * 8}s`,
            pointerEvents: 'none'
          }}
        />
      ))}

      <Container maxWidth="sm" sx={{ position: 'relative', zIndex: 10 }}>
        <Paper
          elevation={24}
          sx={{
            p: 4,
            background: 'rgba(26, 31, 46, 0.95)',
            backdropFilter: 'blur(20px) saturate(180%)',
            border: '1px solid rgba(0, 255, 100, 0.1)',
            borderRadius: 3,
            boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.8), 0 0 0 1px rgba(0, 255, 100, 0.05)',
            position: 'relative',
            overflow: 'hidden',
            '&::before': {
              content: '""',
              position: 'absolute',
              top: 0,
              left: 0,
              right: 0,
              height: '1px',
              background: 'linear-gradient(90deg, transparent, rgba(0, 255, 100, 0.5), transparent)'
            }
          }}
        >
          {/* Logo e Título */}
          <Box sx={{ textAlign: 'center', mb: 4 }}>
            <Typography
              variant="h3"
              component="h1"
              sx={{
                fontWeight: 700,
                mb: 1,
                background: 'linear-gradient(135deg, #00ff64 0%, #00d4ff 100%)',
                backgroundClip: 'text',
                WebkitBackgroundClip: 'text',
                WebkitTextFillColor: 'transparent',
                textShadow: '0 0 30px rgba(0, 255, 100, 0.3)',
                fontSize: { xs: '2rem', sm: '2.5rem' }
              }}
            >
              Nautilus
            </Typography>
            <Typography
              variant="h6"
              sx={{
                color: 'rgba(255, 255, 255, 0.7)',
                fontWeight: 300,
                letterSpacing: '0.5px'
              }}
            >
              Automação Inteligente
            </Typography>
          </Box>

          {/* Formulário de Login */}
          <Box component="form" onSubmit={handleSubmit} sx={{ mb: 4 }}>
            {error && (
              <Alert
                severity="error"
                sx={{
                  mb: 3,
                  backgroundColor: 'rgba(255, 100, 100, 0.1)',
                  border: '1px solid rgba(255, 100, 100, 0.3)',
                  color: '#ff6464',
                  '& .MuiAlert-icon': {
                    color: '#ff6464'
                  }
                }}
              >
                {error}
              </Alert>
            )}

            <TextField
              name="email"
              type="email"
              label="Email"
              value={formData.email}
              onChange={handleChange}
              required
              fullWidth
              margin="normal"
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <Email sx={{ color: 'rgba(0, 255, 100, 0.7)' }} />
                  </InputAdornment>
                ),
              }}
              sx={{
                '& .MuiOutlinedInput-root': {
                  backgroundColor: 'rgba(0, 0, 0, 0.2)',
                  borderRadius: 2,
                  '& fieldset': {
                    borderColor: 'rgba(0, 255, 100, 0.3)',
                  },
                  '&:hover fieldset': {
                    borderColor: 'rgba(0, 255, 100, 0.5)',
                  },
                  '&.Mui-focused fieldset': {
                    borderColor: '#00ff64',
                    boxShadow: '0 0 0 2px rgba(0, 255, 100, 0.1)',
                  },
                },
                '& .MuiInputLabel-root': {
                  color: 'rgba(255, 255, 255, 0.7)',
                },
                '& .MuiInputBase-input': {
                  color: 'white',
                },
              }}
            />

            <TextField
              name="password"
              type={showPassword ? 'text' : 'password'}
              label="Senha"
              value={formData.password}
              onChange={handleChange}
              required
              fullWidth
              margin="normal"
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <Lock sx={{ color: 'rgba(0, 255, 100, 0.7)' }} />
                  </InputAdornment>
                ),
                endAdornment: (
                  <InputAdornment position="end">
                    <IconButton
                      onClick={togglePasswordVisibility}
                      edge="end"
                      sx={{ color: 'rgba(255, 255, 255, 0.7)' }}
                    >
                      {showPassword ? <VisibilityOff /> : <Visibility />}
                    </IconButton>
                  </InputAdornment>
                ),
              }}
              sx={{
                '& .MuiOutlinedInput-root': {
                  backgroundColor: 'rgba(0, 0, 0, 0.2)',
                  borderRadius: 2,
                  '& fieldset': {
                    borderColor: 'rgba(0, 255, 100, 0.3)',
                  },
                  '&:hover fieldset': {
                    borderColor: 'rgba(0, 255, 100, 0.5)',
                  },
                  '&.Mui-focused fieldset': {
                    borderColor: '#00ff64',
                    boxShadow: '0 0 0 2px rgba(0, 255, 100, 0.1)',
                  },
                },
                '& .MuiInputLabel-root': {
                  color: 'rgba(255, 255, 255, 0.7)',
                },
                '& .MuiInputBase-input': {
                  color: 'white',
                },
              }}
            />

            <Button
              type="submit"
              fullWidth
              variant="contained"
              disabled={loading}
              sx={{
                mt: 3,
                mb: 2,
                py: 1.5,
                background: 'linear-gradient(135deg, #00ff64 0%, #00d4ff 100%)',
                color: 'black',
                fontWeight: 600,
                fontSize: '1.1rem',
                borderRadius: 2,
                textTransform: 'none',
                boxShadow: '0 8px 25px rgba(0, 255, 100, 0.3)',
                '&:hover': {
                  background: 'linear-gradient(135deg, #00e055 0%, #00bfee 100%)',
                  boxShadow: '0 12px 35px rgba(0, 255, 100, 0.4)',
                  transform: 'translateY(-2px)',
                },
                '&:disabled': {
                  background: 'rgba(255, 255, 255, 0.1)',
                  color: 'rgba(255, 255, 255, 0.5)',
                },
                transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
              }}
            >
              {loading ? (
                <>
                  <CircularProgress size={20} sx={{ mr: 1, color: 'inherit' }} />
                  Entrando...
                </>
              ) : (
                'Entrar'
              )}
            </Button>
          </Box>

          {/* Seção de Registro */}
          <Box sx={{ textAlign: 'center', mb: 4 }}>
            <Typography variant="h6" sx={{ color: 'white', mb: 2, fontWeight: 500 }}>
              Novo usuário?
            </Typography>

            <Button
              variant="outlined"
              onClick={handleOpenPaymentModal}
              sx={{
                mr: 2,
                mb: 1,
                color: '#00ff64',
                borderColor: '#00ff64',
                fontWeight: 600,
                '&:hover': {
                  borderColor: '#00e055',
                  backgroundColor: 'rgba(0, 255, 100, 0.1)',
                },
              }}
            >
              Registre-se
            </Button>

            <Typography component="span" sx={{ color: 'rgba(255, 255, 255, 0.5)', mx: 1 }}>
              ou
            </Typography>

            <Link
              component={RouterLink}
              to="/register"
              sx={{
                color: '#00d4ff',
                textDecoration: 'none',
                fontWeight: 500,
                '&:hover': {
                  textDecoration: 'underline',
                  color: '#00bfee'
                }
              }}
            >
              🔑 Registrar com Código de Convite
            </Link>
          </Box>

          {/* Links Sociais */}
          <Box sx={{ textAlign: 'center', pt: 3, borderTop: '1px solid rgba(255, 255, 255, 0.1)' }}>
            <Typography variant="body2" sx={{ color: 'rgba(255, 255, 255, 0.6)', mb: 2 }}>
              Siga-nos nas redes sociais
            </Typography>
            <Box sx={{ display: 'flex', justifyContent: 'center', gap: 2 }}>
              <IconButton
                href="https://instagram.com/nautilus.automacao"
                target="_blank"
                rel="noopener noreferrer"
                sx={{
                  color: 'rgba(255, 255, 255, 0.6)',
                  '&:hover': {
                    color: '#E4405F',
                    transform: 'translateY(-2px)',
                  },
                  transition: 'all 0.3s ease',
                }}
              >
                <Instagram />
              </IconButton>
              <IconButton
                href="https://youtube.com/@nautilus.automacao"
                target="_blank"
                rel="noopener noreferrer"
                sx={{
                  color: 'rgba(255, 255, 255, 0.6)',
                  '&:hover': {
                    color: '#FF0000',
                    transform: 'translateY(-2px)',
                  },
                  transition: 'all 0.3s ease',
                }}
              >
                <YouTube />
              </IconButton>
              <IconButton
                href="https://t.me/nautilusautomacao"
                target="_blank"
                rel="noopener noreferrer"
                sx={{
                  color: 'rgba(255, 255, 255, 0.6)',
                  '&:hover': {
                    color: '#0088cc',
                    transform: 'translateY(-2px)',
                  },
                  transition: 'all 0.3s ease',
                }}
              >
                <TelegramIcon />
              </IconButton>
            </Box>
          </Box>
        </Paper>
      </Container>

      {/* Modal de Opções de Pagamento */}
      <Dialog
        open={showPaymentModal}
        onClose={handleClosePaymentModal}
        maxWidth="md"
        fullWidth
        PaperProps={{
          sx: {
            background: 'rgba(26, 31, 46, 0.95)',
            backdropFilter: 'blur(20px) saturate(180%)',
            border: '1px solid rgba(0, 255, 100, 0.1)',
            borderRadius: 3,
            color: 'white'
          }
        }}
      >
        <DialogTitle sx={{ 
          display: 'flex', 
          justifyContent: 'space-between', 
          alignItems: 'center',
          borderBottom: '1px solid rgba(255, 255, 255, 0.1)',
          pb: 2,
          fontWeight: 600,
          background: 'linear-gradient(135deg, #00ff64 0%, #00d4ff 100%)',
          backgroundClip: 'text',
          WebkitBackgroundClip: 'text',
          WebkitTextFillColor: 'transparent'
        }}>
          Opções de Registro
          <IconButton onClick={handleClosePaymentModal} sx={{ color: 'white' }}>
            <Close />
          </IconButton>
        </DialogTitle>

        <DialogContent sx={{ py: 3 }}>
          <Typography variant="body1" sx={{ mb: 3, color: 'rgba(255, 255, 255, 0.8)' }}>
            Escolha uma das opções abaixo para se registrar no Nautilus:
          </Typography>

                     {/* Seção Assinatura */}
           <Box sx={{ mb: 4 }}>
             <Typography variant="h6" sx={{ 
               mb: 1, 
               color: 'white',
               display: 'flex',
               alignItems: 'center',
               gap: 1
             }}>
               <Subscriptions sx={{ color: '#00ff64' }} />
               Assinatura Mensal
             </Typography>
             <Typography variant="body2" sx={{ 
               color: 'rgba(255, 255, 255, 0.7)',
               mb: 3,
               fontStyle: 'italic'
             }}>
               (não necessita recarregar a conta)
             </Typography>

             <Box
               onClick={() => handlePaymentClick(paymentOptions.subscription.link)}
               sx={{
                 p: 3,
                 border: '1px solid rgba(0, 255, 100, 0.3)',
                 borderRadius: 2,
                 background: 'linear-gradient(135deg, rgba(0, 255, 100, 0.05) 0%, rgba(0, 212, 255, 0.05) 100%)',
                 cursor: 'pointer',
                 transition: 'all 0.3s ease',
                 textAlign: 'center',
                 '&:hover': {
                   background: 'linear-gradient(135deg, rgba(0, 255, 100, 0.1) 0%, rgba(0, 212, 255, 0.1) 100%)',
                   borderColor: 'rgba(0, 255, 100, 0.5)',
                   transform: 'translateY(-2px)',
                   boxShadow: '0 8px 25px rgba(0, 255, 100, 0.15)',
                 }
               }}
             >
               <Typography variant="h5" sx={{
                 background: 'linear-gradient(135deg, #00ff64 0%, #00d4ff 100%)',
                 backgroundClip: 'text',
                 WebkitBackgroundClip: 'text',
                 WebkitTextFillColor: 'transparent',
                 fontWeight: 600,
                 mb: 1
               }}>
                 {paymentOptions.subscription.title}
               </Typography>
               <Typography variant="h6" sx={{
                 color: 'white',
                 fontWeight: 500
               }}>
                 {paymentOptions.subscription.price}
               </Typography>
               <Typography variant="body2" sx={{
                 color: 'rgba(255, 255, 255, 0.6)',
                 mt: 1
               }}>
                 Clique para assinar →
               </Typography>
             </Box>
           </Box>

                     {/* Seção Recarga */}
           <Box>
             <Typography variant="h6" sx={{ 
               mb: 1, 
               color: 'white',
               display: 'flex',
               alignItems: 'center',
               gap: 1
             }}>
               <AccountBalance sx={{ color: '#00d4ff' }} />
               Recarga de Conta
             </Typography>
             <Typography variant="body2" sx={{ 
               color: 'rgba(255, 255, 255, 0.7)',
               mb: 3,
               fontStyle: 'italic'
             }}>
               (sem assinatura)
             </Typography>

             <Box sx={{ 
               display: 'flex', 
               flexWrap: 'wrap', 
               gap: 1.5,
               justifyContent: 'center'
             }}>
               {paymentOptions.recharge.map((option, index) => (
                 <Box
                   key={index}
                   onClick={() => handlePaymentClick(option.link)}
                   sx={{
                     display: 'flex',
                     flexDirection: 'column',
                     alignItems: 'center',
                     justifyContent: 'center',
                     p: 1.5,
                     minWidth: '90px',
                     border: '1px solid rgba(255, 255, 255, 0.1)',
                     borderRadius: 2,
                     backgroundColor: 'rgba(255, 255, 255, 0.02)',
                     cursor: 'pointer',
                     transition: 'all 0.2s ease',
                     position: 'relative',
                     '&:hover': {
                       backgroundColor: 'rgba(0, 212, 255, 0.08)',
                       borderColor: 'rgba(0, 212, 255, 0.4)',
                       transform: 'translateY(-2px)',
                       boxShadow: '0 4px 12px rgba(0, 212, 255, 0.15)',
                     }
                   }}
                 >
                   {option.isTest && (
                     <Chip 
                       label="Teste" 
                       size="small" 
                       sx={{ 
                         position: 'absolute',
                         top: -8,
                         right: -8,
                         height: '16px',
                         fontSize: '0.65rem',
                         background: 'rgba(255, 193, 7, 0.2)',
                         color: '#ffc107',
                         border: '1px solid rgba(255, 193, 7, 0.4)',
                         fontWeight: 500
                       }} 
                     />
                   )}

                   <ShoppingCart sx={{ 
                     color: '#00d4ff', 
                     fontSize: '20px',
                     mb: 0.5
                   }} />

                   <Typography variant="body2" sx={{ 
                     color: 'white', 
                     fontWeight: 500,
                     fontSize: '0.85rem'
                   }}>
                     {option.value}
                   </Typography>
                 </Box>
               ))}
             </Box>
           </Box>

          <Box sx={{ mt: 3, p: 2, backgroundColor: 'rgba(0, 255, 100, 0.05)', borderRadius: 2 }}>
            <Typography variant="body2" sx={{ color: 'rgba(255, 255, 255, 0.8)', textAlign: 'center' }}>
              💡 <strong>Como funciona:</strong> Após o pagamento ser confirmado, você será redirecionado automaticamente para a página de registro com acesso liberado.
            </Typography>
          </Box>
        </DialogContent>
      </Dialog>
    </Box>
  );
};

export default Login;
